// Solution
function optimizeTask(tasks, updateTasks) {
  // Your code here
  return {
    tasks: updateTasks(tasks),
    reRendered: tasks === updateTasks(tasks)
  };
}

function updateTasks(tasks) {
  return tasks.map((task) => ({...task, name: task.name + " updated"}));
}

solutions.python:
class Solution:
  def optimize_task(self, tasks, update_tasks):
    # Your code here
    return {
      "tasks": update_tasks(tasks),
      "re_rendered": tasks == update_tasks(tasks)
    }

  def update_tasks(self, tasks):
    return [task for task in tasks]  # This will create new references
